type SafeCounter struct {
    mu sync.Mutex
    count map[string]int
}

func (c *SafeCounter) Inc(key string) {
    c.mu.Lock()         // 잠금!
    defer c.mu.Unlock() // 해제!
    c.count[key]++
}

func (c *SafeCounter) Get(key string) int {
    c.mu.Lock()
    defer c.mu.Unlock()
    return c.count[key]
}

func main() {
    c := SafeCounter{
        count: make(map[string]int)}
    for i := 0; i < 1000; i++ {
        go c.Inc("key")
    }
    time.Sleep(time.Second)
    fmt.Println(c.Get("key")) // 1000 ✅
}

// Fan-Out: 하나의 입력 → 여러 워커
// Fan-In: 여러 워커 → 하나의 출력
func worker(id int,
    jobs <-chan int,
    results chan<- int) {
    for j := range jobs {
        fmt.Printf("워커%d: 작업%d 처리\n",
            id, j)
        time.Sleep(time.Second)
        results <- j * 2
    }
}

func main() {
    jobs := make(chan int, 100)
    results := make(chan int, 100)

    // Fan-Out: 3개 워커 실행
    for w := 1; w <= 3; w++ {
        go worker(w, jobs, results)
    }

    // 작업 전송
    for j := 1; j <= 9; j++ {
        jobs <- j
    }
    close(jobs)

    // Fan-In: 결과 수집
    for i := 0; i < 9; i++ {
        fmt.Println(<-results)
    }
}

