func FetchAll(ctx context.Context,
    urls []string) ([]Response, error) {
    g, ctx := errgroup.WithContext(ctx)
    results := make([]Response, len(urls))

    for i, url := range urls {
        g.Go(func() error {
            resp, err := FetchURL(ctx, url)
            if err != nil {
                return err // 에러 → 전체 취소!
            }
            results[i] = resp
            return nil
        })
    }

    // 모든 고루틴 완료 대기
    if err := g.Wait(); err != nil {
        return nil, err
